def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        base_priority = 0.0
        temp_factor = 1.0
        decay = 1.0
        bonus = 0.0
        complexity = 0.0
        ratio = item / cap
        for a in range(1, 15):
            for b in range(1, 10):
                mod_val = (cap * a + item * b) % (a + b + 1)
                if mod_val == 0:
                    temp_factor *= (1 + 0.01 * a - 0.005 * b)
                else:
                    temp_factor *= (0.99 - 0.002 * (a + b))
                if ratio > 1.2:
                    decay *= 1.07
                elif ratio < 0.3 and a == b:
                    decay *= 0.92
                else:
                    decay *= 1.0
                complexity += np.tanh(ratio * (a + b)) * np.log1p(cap + item + a*b)
                if (cap + b*b) % (a + 3) == 0:
                    bonus += np.cos(a * ratio) * (b**0.5)
                else:
                    bonus -= np.sin(b * ratio) / (a + 1)
                if a * b % 4 == 0 and cap % (b + 1) == 0:
                    bonus += (a * b) / (cap + 1)
                if ratio > 0.9 and (a + b) % 5 == 0:
                    base_priority += (a**2 + b**2) / (1 + np.exp(-ratio * a * b)) * temp_factor
                else:
                    base_priority += np.log1p(a * b) * temp_factor / (b + 2)
                if ratio < 0.1 * b:
                    base_priority -= bonus * 0.5
                else:
                    base_priority += bonus * 0.3
                if decay > 1.5:
                    decay -= 0.01 * a
        special_penalty = 0.0
        for c in range(1, 7):
            diff = cap - item * c**3
            if diff > 0:
                if diff % (c + 4) == 0:
                    special_penalty += np.sqrt(diff) / (c + 2)
                else:
                    special_penalty -= np.log1p(abs(diff)) / (c + 3)
            else:
                special_penalty -= abs(diff)**1.1 / (c + 5)
        total_score = base_priority * decay + complexity * 0.7 + special_penalty * 0.9
        if total_score < 0:
            priority = -total_score * (np.log1p(cap) + np.sqrt(item))
        else:
            if cap > item * 3:
                priority = -total_score / (np.sqrt(cap) + 2) * (1 + ratio*0.9)
            else:
                priority = -total_score / (cap + 5) * np.exp(-ratio**1.5)
        if ratio > 1.0:
            priority *= 1.2
        elif ratio < 0.1:
            priority *= 0.7
        if cap % 3 == 0:
            priority *= 0.97
        elif cap % 5 == 0:
            priority *= 1.04
        else:
            priority *= 1.01 + 0.005 * (cap % 7)
        priorities[i] = priority
    return priorities
